INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, "シズルさまにエリコさま、\nどうかされたのですか？", 10, 0, 0, 19050041, 0.5, 1, 107611, 11, 905);
