INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, "あら、タマキさんじゃない。\nこんなところで何やってるの？", 10, 0, 0, 19440030, 1, 1, 126811, 11, 944);
