INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, "なんだ、ユカリだったかにゃ。\n何ってもちろん商売にゃ！", 10, 0, 0, 19440033, 1, 1, 107911, 11, 944);
